@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products..."
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search__status">Searching...</div>
    }
    else if (_error is not null)
    {
        <div class="product-search__error">
            <p>Something went wrong: @_error</p>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search__status">No products found.</div>
    }
    else if (_results.Count > 0)
    {
        <div class="product-search__results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" class="product-card__image" />
                    <div class="product-card__info">
                        <h3 class="product-card__name">@product.Name</h3>
                        <p class="product-card__price">@product.Price.ToString("C")</p>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private Timer? _debounceTimer;
    private CancellationTokenSource? _searchCts;

    private void OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;
        _error = null;

        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(DebounceElapsed, null, 300, Timeout.Infinite);
    }

    private async void DebounceElapsed(object? state)
    {
        await InvokeAsync(ExecuteSearch);
    }

    private async Task ExecuteSearch()
    {
        var query = _query.Trim();

        if (string.IsNullOrEmpty(query))
        {
            _results = new();
            _hasSearched = false;
            _error = null;
            StateHasChanged();
            return;
        }

        // Cancel any in-flight search
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = new CancellationTokenSource();
        var ct = _searchCts.Token;

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            _results = await ProductService.SearchAsync(query, ct);
            _hasSearched = true;
            _error = null;
        }
        catch (OperationCanceledException)
        {
            // Search was superseded by a newer query; do nothing.
            return;
        }
        catch (Exception ex)
        {
            _results = new();
            _error = ex.Message;
        }
        finally
        {
            if (!ct.IsCancellationRequested)
            {
                _isLoading = false;
            }
        }

        StateHasChanged();
    }

    private async Task RetrySearch()
    {
        await ExecuteSearch();
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    public void Dispose()
    {
        _debounceTimer?.Dispose();
        _searchCts?.Cancel();
        _searchCts?.Dispose();
    }
}

